INSERT INTO gamedb.NPC_List (ID, Name, Game_File, Message1, Message2, Message3, Message4, Event_Type, Event_Param, Skill_Quests, Quest_ID, Quest_Type_ID, Quest_Type_Sub_ID, Teleport_ID, Weapon_Shop, Defense_Shop, Misc_Shop) OVERRIDING SYSTEM VALUE VALUES
(1, 'Mushroom Cave Keeper', 'char\\npc\\TN-001\\TN-001.INI', 'I am guarding the Mushroom Cave.', 'Mysterious creatures are all around in this mysterious cave...', 'On the end of the cave you can enter Dark Sanctuary, you must be quite strong to enter that though!', 'Mushroom Cave used to be a peaceful place, but now it is filled with evil monsters!', 0, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(2, 'Miscellaneous Store, Lynn', 'char\\npc\\TN-005\\TN-005.INI', 'Hello, how can I help you?', 'Look out, dangerous monsters are all around here!', 'You look like you need some medical care! Buy a few potions.', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104 ec101 ec104 '),
(3, 'Miscellaneous Store, Lette', 'char\\npc\\Bcn03\\Bcn03.INI', 'If you are about to enter the Cursed Temple, make sure you got some potions with you!', 'Have you seen the strong monster Ratoo? That monster is very dangerous!', 'Fortunately the curse of the temple holds the evil monsters inside forever...', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104 ec101 ec104 '),
(4, 'Cursed Temple Guardian', 'char\\npc\\MN-006\\MN-006.INI', 'Only warriors from above level 70 may enter the Cursed Temple...', 'The Cursed Temple is has a second floor, which requires atleast level 75!', 'Once you enter the Fury Arena in Cursed Temple Floor 2... You will never get out...', NULL, 0, 0, 0, 1005, 0, 0, 0, NULL, NULL, NULL),
(5, 'Blacksmith Frain', 'char\\npc\\MN-004\\MN-004.INI', 'Hi, are you looking for some nice equipments?', 'Please take a look at my store, I have what you need!', 'Do you have something valuable you want to sell to me?', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(6, 'Blacksmith Andrew', 'char\\npc\\MN-003\\MN-003.INI', 'Hi, are you looking for nice equipment?', 'Please take a look at my store, I have what you need!', 'Do you have something valuable you want to sell to me?', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(7, 'Event Girl', 'char\\npc\\TN-016\\TN-016.INI', 'Do you need to redistribute your statistic points or skill points?', 'You are cute! ^^', 'Hellow!! Come dance with me ^_^', NULL, 1, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(8, 'Force Master', 'char\\npc\\MN-013\\MN-013.INI', 'Hi there, how can I help you?', 'Have you met my brothers, the Force Masters?', NULL, NULL, 4, 0, 0, 0, 0, 0, 0, NULL, NULL, 'FO101 FO102 FO103 FO104 FO105 FO106 FO107 FO108 FO109'),
(9, 'Gardener Omi', 'char\\npc\\atlantis\\1\\1.INI', 'I am in charge of maintaining the beautiful Gardens of Atlantis!', 'Hmm... Have you solved any mysteries yet?', NULL, NULL, 0, 0, 0, 0, 0, 0, 33, NULL, NULL, NULL),
(10, 'Atlantis Guard', 'char\\npc\\atlantis\\8\\8a.INI', 'Welcome to the peaceful city of Atlantis', 'Hello! Can I do something for you?', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(11, 'Atlantis Guard', 'char\\npc\\atlantis\\8\\8a.INI', 'Welcome to Atlantis Town!', 'Hello there! What brings you here?', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(12, 'Hair Stylelist', 'char\\npc\\atlantis\\7\\7.INI', 'Do you need a hair potion?', 'How can I help you?', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'BI116 BI117 BI118 BI213 BI214 BI215 BI216 BI217 BI218 BI219 BI220 BI221 BI222'),
(13, 'Huntress', 'char\\npc\\atlantis\\7\\7.INI', 'Any crystals you need?', 'I have been hunting crystals all my life!', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'gp101 gp102 gp103 gp104'),
(14, 'Item Collector, Linh', 'char\\npc\\atlantis\\1\\1.INI', 'I collect special items! Do you have any?', 'If you have special items, bring them to me and I will reward you!', NULL, NULL, 0, 0, 0, 0, 0, 0, 31, NULL, NULL, NULL),
(15, 'Item Distributor', 'char\\npc\\TN-014\\TN-014.INI', 'Let me see if I have something for you...', 'If I have something for you, come get it here as quickly as possible!', NULL, NULL, 2, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(16, 'Mayor Maz', 'char\\npc\\atlantis\\3\\3.INI', 'Welcome to Atlantis Town!', 'Enjoy your stay in Atlantis Town!', NULL, NULL, 9, 0, 0, 0, 0, 0, 1000, NULL, NULL, NULL),
(17, 'Battle Portal', 'char\\npc\\bt03\\battleportal.INI', 'Hello, how can I help you?', 'I can teleport you to Battle Town if you want...', NULL, NULL, 9, 0, 0, 0, 0, 0, 1002, NULL, NULL, NULL),
(18, 'Precious Item Shop', 'char\\npc\\Bcn05\\Bcn05.INI', 'These precious items hold great value!', 'You can buy and sell these precious items for the same gold!', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'GB101 GB102 GB103'),
(19, 'Atlantis Prison Guard', 'char\\npc\\atlantis\\8\\8a.INI', 'I protect this prison, do not get close!', 'What are you doing here? Get lost!', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(20, 'Atlantis Special Item Shop', 'char\\npc\\Bcn05\\Bcn05.INI', 'These items are very special, use them wise!', 'How do you like Atlantis Town so far?', 'Have you been to Battle Town yet?', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'BI104 BI106 BI107 BI108 BI119 BI120 BI121 BI122'),
(21, 'Stonesmith Hong', 'char\\npc\\atlantis\\5\\5.INI', 'Need a unique stone? I got them!', 'Have you been to Battle Town yet?', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'se103 se102 se101 rs101 ms101 ms102 ms103'),
(22, 'Supply Store, Ny', 'char\\npc\\atlantis\\4\\4.INI', 'Need supply? Get it here!', 'I have every potion you need.', 'How can I help?', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104 EC101 EC104'),
(23, 'Warehouse Keeper, Doj', 'char\\npc\\Bcn06\\Bcn06.INI', 'Need to store items? This is the right place!', 'Let me see if I got some stored items of yours here...', NULL, NULL, 30, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(24, 'Clever Daemon', 'char\\npc\\MN-013\\MN-013.INI', 'Need to warp to Bless Castle? This is the place!', 'Enjoy the battle!', 'Every week a great siege war takes place in Bless Castle, don''t miss it!', NULL, 9, 0, 0, 0, 0, 0, 2, NULL, NULL, NULL),
(25, 'Battle Controls', 'char\\npc\\bt05\\battlecontrols.INI', 'Clan leaders and members can view and manage their settings and view their score here!', 'Welcome to Battle Town! Enjoy your stay!', NULL, NULL, 0, 0, 0, 0, 0, 0, 24, NULL, NULL, NULL),
(26, 'Force Master', 'char\\npc\\MN-012\\MN-012.INI', 'Once you use a force, you can not use it again, so use it wisely!', 'Got sheltoms you need me to turn into forces?', 'You can only use one force at a time!', NULL, 4, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(27, 'Battle Guard', 'char\\npc\\bt04\\battleguard.INI', 'I am one of the four guards of Battle Town.', 'Nothing goes in this town without passing me first!', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(28, 'Battle Master', 'char\\npc\\bt01\\battlemaster.INI', 'Be well prepared before you enter Battle Arena!', 'Are you ready to enter Battle Arena?', 'Many battles take place every day in this arena, try it yourself too!', NULL, 0, 0, 0, 0, 0, 0, 25, NULL, NULL, NULL),
(29, 'Battle Portal', 'char\\npc\\bt03\\battleportal.INI', 'Hello, welcome to Battle Town!', 'Do you need to be warped back to Atlantis Town?', NULL, NULL, 0, 0, 0, 0, 0, 0, 30, NULL, NULL, NULL),
(30, 'Mystery Portal', 'char\\npc\\bt07\\mysteryportal.INI', 'I can warp you to Mystery Desert, but you must be strong enough!', 'I can only warp you to Mystery Desert if you have a Warrior Certificate!', 'Welcome to Battle Town! How can I help?', NULL, 0, 0, 0, 0, 0, 0, 21, NULL, NULL, NULL),
(31, 'Battle Potion Store', 'char\\npc\\bt02\\battlepotion.INI', 'Need supply? This is the right place!', 'I got any potion you need!', 'Be quick! I am sold out soon!', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104'),
(32, 'Secretary Dunnavan', 'char\\npc\\bt06\\battlequest.INI', 'Let me see if I have a quest for you...', 'Are you on a quest?', 'Do you want a quest?', NULL, 0, 0, 0, 0, 0, 0, 26, NULL, NULL, NULL),
(33, 'Sanctuary Keeper', 'char\\npc\\MN-013\\MN-013.INI', 'Hello, I can warp you to Forgotten Sanctuary if you want...', 'Do you want to be warped to Forgotten Sanctuary?', NULL, NULL, 0, 0, 0, 0, 0, 0, 28, NULL, NULL, NULL),
(34, 'Esu, The Manager', 'char\\npc\\Bcn05\\Bcn05.INI', 'Only the clan leader of the Bless Castle Clan can manage these settings!', 'Congratulations on your victory!', 'Eeesuu, HAHAHAHAHAHAHAAHAH', 'watch?v=m623lGdROE0', 5, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(35, 'Bless Castle Guard', 'char\\npc\\TN-001\\TN-001.INI', 'Every week a siege war takes place in Bless Castle, don''t miss it!', 'Are you well prepared to battle?', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(36, 'Rossa', 'char\\npc\\Bcn02\\Bcn02.INI', 'Anything you need!', 'How can I help?', 'Good Luck!', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104 BC109 BC110 BC111 BC112 BC113 BC114 BC115 BC116 EC101'),
(37, 'Shellbi', 'char\\npc\\Bcn03\\Bcn03.INI', 'I will not be around during siege war, so be well prepared before it begins!', 'Victory shall be yours!', 'I Love GM-P! =)', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104 BC102 BC103 EC101 ec104'),
(38, 'Rozalie', 'char\\npc\\Bcn04\\Bcn04.INI', 'Good Luck, I hope you win!', 'You look strong enough to defeat anyone, really!', 'I have enough potions for everyone, so don''t worry about that!', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104 BC106 BC107 BC108 EC101 ec104'),
(39, 'Kara', 'char\\npc\\Bcn01\\Bcn01.INI', 'Congratulations on your victory, I will serve you for one week!', 'If you need Mana Potions, go to the Mana Fountain.', 'Warping to Bless Castle is free when using the Warp Gate!', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104'),
(40, 'Kiri', 'char\\npc\\Bcn01\\Bcn01.INI', 'How are you doing?', 'Need scrolls? I got them!', 'Good Luck in the next siege, hope you win!', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'BC102 BC103 BC104 BC105 GP114 GP115 GP116'),
(41, 'Dungeon Keeper', 'char\\npc\\TN-001\\TN-001.INI', 'You must be atleast level 40 to enter the dungeons!', 'Are you level 40?', 'I got potions and ether cores.', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL102 PL103 PL104 PS102 PS103 PS104 EC101 EC104'),
(42, 'Cursed Land Bridge Guard', 'char\\npc\\TN-001\\TN-001.INI', 'Only pass this bridge if you are confident of your strength!', 'If you continue, you will eventually reach Navisko Town!', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(43, 'Miscellaneous Store, Savy', 'char\\npc\\Bcn04\\Bcn04.INI', 'Don''t bring those scary monsters here, or I''ll scream!!!', 'Eek! A scary monster!! Oh it''s just you...', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104 ec101 ec104 '),
(44, 'Eura Force Master', 'char\\npc\\IceN-03\\IceN-03.INI', 'Once you use a force, you can not use it again, so use it wisely!', 'Once you use a force, you can not use it again, so use it wisely!', 'Once you use a force, you can not use it again, so use it wisely!', 'Once you use a force, you can not use it again, so use it wisely!', 4, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(45, 'Eura Guard, Andrei', 'char\\npc\\TN-002\\TN-002.INI', 'Continue on and you will reach Kelvezu Lair...', 'Let me see if I have a quest for you...', 'Beware, dangerous fields are beyond this point!', NULL, 0, 0, 0, 1006, 0, 0, 0, NULL, NULL, NULL),
(46, 'Miscellaneous Store, Eura', 'char\\npc\\IceN-02\\IceN-02.INI', 'Need supplies in this chilling environment?', 'I have all the potions you need!', 'I have to unfreeze those potions before I can sell them, it''s so cold here!', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104 ec101 ec104'),
(47, 'Warehouse keeper, Eura', 'char\\npc\\IceN-01\\IceN-01.INI', 'Let me see if I have any stored items for you...', 'Need to store an item for later? I can do it for you!', NULL, NULL, 30, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(48, 'Supply Store, Resia', 'char\\npc\\Bcn03\\Bcn03.INI', 'Are you on your way to the Ancient Dungeons?', 'Be careful if you continue...', 'Make sure you have enough potions!', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104 ec101 ec104'),
(49, 'Eura Iron Guard', 'char\\npc\\TN-002\\TN-002.INI', 'Be careful, I don''t trust any of these creatures!', 'Good Luck!', 'Welcome to Eura Village.', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(50, 'Iron Guard', 'char\\npc\\TN-002\\TN-002.INI', 'Continue on and you will reach Eura Village at the end!', 'Are you ready to move from a machinery environment to a freezing one!', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(51, 'Miscellaneous Store, Robin', 'char\\npc\\Bcn02\\Bcn02.INI', 'Be careful, Kelvezu is very strong!', 'Kelvezu only appears a few times per day...', 'Are you ready to battle Kelvezu?', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104 ec101 ec104'),
(52, 'Cave Guard', 'char\\npc\\MN-002\\MN-002.INI', 'You must be at least level 55 to enter this cave!', 'Are you ready to enter the cave?', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(53, 'Pitchman Dela', 'char\\npc\\MN-005\\MN-005.INI', 'How are you? I got potions for you.', 'Making good progress already?', 'You are becoming very skillful already!', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104'),
(54, 'Lost Castle Bridge Guard', 'char\\npc\\TN-001\\TN-001.INI', 'Pass this bridge and you will enter Ruinen Village!', 'There is a camp in Ruinen Village, you can''t miss it!', 'Say hello from me will you?', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(55, 'Miscellaneous Store, Evy', 'char\\npc\\Bcn02\\Bcn02.INI', 'Quick, before those creatures reach this place!', 'Defeat those scary monsters please!', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104 ec101 ec104'),
(56, 'Cursed Milter', 'char\\npc\\milter\\milter.INI', 'I can warp you to Endless Tower, but you must be at least level 110!', 'Are you well prepared? Very strong monsters reside in these towers!', NULL, NULL, 0, 0, 0, 0, 0, 0, 23, NULL, NULL, NULL),
(57, 'Miscellaneous Store, Ivonne', 'char\\npc\\Bcn04\\Bcn04.INI', 'Hello, how can I help?', 'Say hello to Miscellaneous Store, Evy if you see her, will you?', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104 ec101 ec104'),
(58, 'Desert Guard', 'char\\npc\\atlantis\\8\\8b.INI', 'Halt! You can continue!', 'Go back or I will have to teleport you back to Battle Town!', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(59, 'Forest Guard', 'char\\npc\\atlantis\\8\\8b.INI', 'Halt! I will warp you back to Atlantis Town if you continue!', 'This is restricted area! Go back!', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(60, 'Mystery Portal', 'char\\npc\\bt07\\mysteryportal.INI', 'I can warp you back to Battle Town.', 'Quick! Before the monsters reach us!', NULL, NULL, 0, 0, 0, 0, 0, 0, 22, NULL, NULL, NULL),
(61, 'Civilian Minuren', 'char\\npc\\TN-006\\TN-006.INI', 'Oh oh, can you help me?', 'Come back again if I don''t have a quest for you now...', NULL, NULL, 0, 0, 0, 1011, 0, 0, 0, NULL, NULL, NULL),
(62, 'Desert Guard', 'char\\npc\\TN-002\\TN-002.INI', 'Are you well prepared?', 'Cursed Temple entrance is in the far end, good luck!', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(63, 'Blacksmith Umph', 'char\\npc\\TN-003\\TN-003.INI', 'Say hello to Blacksmith Drol sometime!', 'How are you doing? Looking for some equipment, aren''t you?', NULL, NULL, 0, 0, 0, 1022, 0, 0, 0, 'ws108 ws109 ws110 ws111 WS208 ws209 ws211 WA106 wa108 wa107 wa109 WH107 wh108 wh109 wh110 WP107 wp108 wp109 wp110 WC106 wc107 wc108 wc109 WT107 wt108 wt109 wt110 wd107 wd108 wd109 wd110', 'DA107 DA108 da109 da110 DB106 DB107 db108 db109 DG106 DG107 dg108 dg109 DS106 DS107 ds108 ds109 OA206 OA207 oa208 oa209', NULL),
(64, 'Blacksmith Drol', 'char\\npc\\MN-004\\MN-004.INI', 'Hello, I am Drol, how can I help?', 'Need equipment? I have almost anything!', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, 'WS112 WS113 WS114 WS212 WS213 WS214 WS215 WA110 WA111 WA112 WH111 WH112 WH113 WP111 WP112 WP113 WC110 WC111 WC112 WT111 WT112 WT113 WD111 WD112 WD113', 'DA111 DA112 DA113 DA114 DB110 DB111 DB112 DG110 DG111 DG112 DS110 DS111 DS112 OA210 OA211 OA212', NULL),
(65, 'Navisko Guard', 'char\\npc\\TN-002\\TN-013.INI', 'Have you heard of the curse of Navisko Town?', 'Strangely... I never remember nights in Navisko Town...', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(66, 'Magic store, 3rd branch', 'char\\npc\\MN-008\\MN-008.INI', 'Ah Hello! How can I help?', 'Need magic equipment? I have it!', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, 'WM107 WM108 WM109 WN107 WN108 WN109', 'DA207 DA208 DA209 OM107 OM108 OM109', NULL),
(67, 'Miscellaneous Store, Byant', 'char\\npc\\TN-005\\TN-005.INI', 'I only have a limited amount of potions, so be quick!', 'The waters of the deserts dry up soon, I don''t know where I can get new potions from...', NULL, NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104 EC101 EC104 EC102'),
(68, 'Warehouse keeper, Omidor', 'char\\npc\\Bcn06\\Bcn06.INI', 'Hello there! Anything I can help you with?', 'Have you tried Survive or Die yet?', NULL, NULL, 30, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(69, 'Arcane Moriph', 'char\\npc\\MN-007\\MN-007.INI', 'Need to age an item?', 'You can age an item up to +20!', 'Aging increases your items statistics!', NULL, 6, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(70, 'Master Arad', 'char\\npc\\arad\\arad.INI', 'Mmmm...', NULL, NULL, NULL, 7, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
(71, 'Molly, the granny', 'char\\npc\\MN-009\\MN-009.INI', 'Oh, can you pick up that coin I dropped?', 'Some people whisper around about a wolve that looks like me... do you know what they mean?', NULL, NULL, 0, 0, 0, 0, 2, 1, 0, NULL, NULL, NULL),
(72, 'Phillai Clan Master', 'char\\npc\\TN-011\\TN-011.INI', 'Controlling of Clans is done here or in Ricarten Town', NULL, NULL, NULL, 8, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
