(193, 'Miscellaneous Store, Kairi', 'char\\npc\\TN-005\\TN-005.INI', 'Hello, how can I help you?', 'Please take care, terrible monsters are lurking in the ruinen houses near the lake!', 'You look like you need some medical care! Buy a few potions.', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104 ec101 ec104 '),
(194, 'Miscellaneous Store, Midna', 'char\\npc\\Bcn03\\Bcn03.INI', 'Hello, how can I help you?', 'It is scary down here! I can hear the monsters roaming the halls. Please take care..', 'You look like you need some medical care! Buy a few potions.', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104 ec101 ec104 '),
(195, 'Miscellaneous Store, Shepard', 'char\\npc\\Bcn05\\Bcn05.INI', 'Hello, how can I help you?', ' I can hear the monsters roaming these halls. Go and slay them all! But first, check if you got enough pots with you!', 'You look like you need some medical care! Buy a few potions.', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104 ec101 ec104 '),
(196, 'Miscellaneous Store, Alyx', 'char\\npc\\Bcn04\\Bcn04.INI', 'Hello, how can I help you?', 'Please take care.. the monsters are strong here!', 'You look like you need some medical care! Buy a few potions.', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104 ec101 ec104 '),
(197, 'Miscellaneous Store, Tifa', 'char\\npc\\Bcn04\\Bcn04.INI', 'Hello, how can I help you?', 'The cave is scary.. I can hear buzzing!! Don''t forget to bring potions with you.', 'You look like you need some medical care! Buy a few potions.', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104 ec101 ec104 '),
(198, 'Miscellaneous Store, Yuna', 'char\\npc\\Bcn02\\Bcn02.INI', 'Hello, how can I help you?', 'The heat is unbearable here so I take refuge in the shade here. These potions will cool you down!', 'You look like you need some medical care! Buy a few potions.', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104 ec101 ec104 '),
(199, 'Miscellaneous Store, Gorden', 'char\\npc\\Bcn05\\Bcn05.INI', 'Welcome to my home! Would you like to come in?', 'What do you think of my lovely home? Thanks to people like you, you made this possible.', 'Buy a few potions. No. Buy many potions! You never know when you will run out.', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, 'PL101 PL102 PL103 PL104 PS101 PS102 PS103 PS104 ec101 ec104 '),
(200, 'Mark, Leaderboard Tracker', 'char\\npc\\Bcn05\\Bcn05.INI', 'Are you on here?', 'These people are amazing!', 'Man I wish I was a good as these guys.', NULL, 27, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
