(202, 'Elite Laboratory Guard', 'char\\npc\\Derik\\derik.INI', 'Secrets hidden long ago, under our protection', 'Be careful out there, dangerous monsters lurk in this Laboratory', 'Only the most skilled Heroes will survive here', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
