(207, 'S2 Warehouse keeper, Aya', 'char\\npc\\MN-010\\MN-010.INI', 'Hello, I transfer Warehouse items from Seasonal Server!', 'You can only withdraw items.', 'I won''t be around forever! So you better withdraw all your items soon!', NULL, 31, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
