(216, 'Mysterious man', 'char\\npc\\enzo\\enzo.ini', 'One day i''ll figure out how those warpgates work.', 'So many secrets remain.', 'You really think the Abyss is all there is?', NULL, 0, 0, 0, 0, 0, 0, 0, NULL, NULL, NULL),
